export function render(rootPageRef: any): void {
  const stepsInfo = ['Step 1', 'Step 2', 'Step 3', 'Step 4'];
  const totalSteps = stepsInfo.length;
  let currentStep = 1;

  const stepperWrapper = __CreateView(rootPageRef);
  __SetClasses(stepperWrapper, "stepper-wrapper");
  __AppendElement(rootPageRef, stepperWrapper);

  const steps = stepsInfo.map((info, index) => {
    const stepElem = __CreateView(stepperWrapper);
    __SetClasses(stepElem, index + 1 === currentStep ? "step filled" : "step empty");
    const textNode = __CreateText(stepElem);
    const rawText = __CreateRawText(info);
    __AppendElement(textNode, rawText);
    __AppendElement(stepElem, textNode);
    __AppendElement(stepperWrapper, stepElem);
    return stepElem;
  });

  const controlsWrapper = __CreateView(rootPageRef);
  __SetClasses(controlsWrapper, "controls-wrapper");
  __AppendElement(rootPageRef, controlsWrapper);

  const prevButton = __CreateView(controlsWrapper);
  __SetClasses(prevButton, "button prev");
  const prevText = __CreateRawText("Back");
  __AppendElement(prevButton, prevText);
  __AddEvent(prevButton, 'click', 'prevClick', () => {
    if (currentStep > 1) {
      __SetClasses(steps[currentStep - 1], "step empty");
      currentStep -= 1;
      __SetClasses(steps[currentStep - 1], "step filled");
    }
  });
  __AppendElement(controlsWrapper, prevButton);

  const nextButton = __CreateView(controlsWrapper);
  __SetClasses(nextButton, "button next");
  const nextText = __CreateRawText("Next");
  __AppendElement(nextButton, nextText);
  __AddEvent(nextButton, 'click', 'nextClick', () => {
    if (currentStep < totalSteps) {
      __SetClasses(steps[currentStep - 1], "step empty");
      currentStep += 1;
      __SetClasses(steps[currentStep - 1], "step filled");
    }
  });
  __AppendElement(controlsWrapper, nextButton);

  __FlushElementTree(rootPageRef);
}

