  __SetClasses(textarea, "markdown-input");
  __AppendElement(wrapperView, textarea);

  // Create a div for markdown preview
  const previewDiv = __CreateElement("div", 0);
  __SetClasses(previewDiv, "markdown-preview");
  __AppendElement(wrapperView, previewDiv);

  // Function to convert markdown to HTML
  const updatePreview = () => {
    const markdownText = <string>__GetAttributeByName(textarea, "value") || "";
    const marked = (window as any).marked; // assuming 'marked' library is loaded globally
    const html = marked(markdownText);
    const rawHtml = __CreateRawText(html);
    __RemoveElement(previewDiv, __FirstElement(previewDiv)); // Clear previous preview
    __AppendElement(previewDiv, rawHtml);
  };

  // Add an input event listener to the textarea
  __AddEvent(textarea, "input", "updatePreview", updatePreview.toString());

  // Flush the element tree
  __FlushElementTree(rootPageRef);
}

